worked_example.final_code:
import java.util.*;

class Product {
    private String name, category;
    private double price, discount;

    Product(String name, String category, double price, double discount) {
        this.name = name; this.category = category;
        this.price = price; this.discount = discount;
    }

    public String getName()     { return name; }
    public String getCategory() { return category; }
    public double getPrice()    { return price; }
    public double getDiscount() { return discount; }
    public double finalPrice()  { return price * (1 - discount / 100); }
    public String toString()    { return name; }
}

public class LambdaSort {
    public static void main(String[] args) {
        List<Product> catalog = new ArrayList<>(Arrays.asList(
            new Product("Mouse",     "Electronics", 799,  10),
            new Product("Keyboard",  "Electronics", 1999, 20),
            new Product("Java Book", "Books",        649,  15),
            new Product("USB Hub",   "Electronics",  499,  25)
        ));

        // Lambda Comparators
        Comparator<Product> byPrice     = (a, b) -> Double.compare(a.getPrice(), b.getPrice());
        Comparator<Product> byFinalPrice = (a, b) -> Double.compare(a.finalPrice(), b.finalPrice());
        Comparator<Product> byName       = (a, b) -> a.getName().compareTo(b.getName());

        // Sort and print with lambda forEach
        catalog.sort(byPrice);
        System.out.println("=== By Price ===");
        catalog.forEach(p -> System.out.printf("%-12s ₹%.0f%n", p.getName(), p.getPrice()));

        catalog.sort(byFinalPrice);
        System.out.println("\n=== By Final Price ===");
        catalog.forEach(p -> System.out.printf("%-12s ₹%.2f (%.0f%% off)%n",
            p.getName(), p.finalPrice(), p.getDiscount()));

        catalog.sort(byName);
        System.out.println("\n=== Alphabetical ===");
        catalog.forEach(p -> System.out.println(p.getName()));
    }
}

